class Solution(object):
    def licenseKeyFormatting(self, s, k):
        s = s.replace('-', '').upper()
        if not s:
            return ''
        n = len(s)
        first = n % k or k
        groups = [s[:first]]
        i = first
        while i < n:
            groups.append(s[i:i+k])
            i += k
        return '-'.join(groups)
